                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Cliente</label>
                  <input type="text" list="client-datalist" value={saveFormData.client} onChange={(e) => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none focus:border-emerald-500/50 transition-all" placeholder="Ex: Coca-Cola" />
                  <datalist id="client-datalist">{clients.map(c => <option key={c} value={c} />)}</datalist>
                </div>
              </div>
              <button 
                type="button"
                onClick={handleSaveToSupabase} 
                disabled={isSyncing || !saveFormData.name.trim()} 
                className="w-full py-5 bg-emerald-500 text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3 disabled:opacity-30 transition-all active:scale-95"
