                    <button key={client} onClick={() => setSelectedClientFilter(client)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedClientFilter === client ? 'bg-emerald-500 text-black border-emerald-500 shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>{client}</button>
                  ))}
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProjects.map(proj => (
                  <div key={proj.id} onClick={() => handleOpenProject(proj)} className={`h-72 bg-zinc-900/40 border rounded-[32px] p-8 flex flex-col justify-between hover:bg-zinc-800/40 transition-all cursor-pointer group relative overflow-hidden ${currentProjectId === proj.id ? 'border-emerald-500 ring-2 ring-emerald-500/20' : 'border-white/5'}`}>

                      {/* Botão de Excluir - REFORMULADO PARA INTERAÇÃO ABSOLUTA */}
                      <button 
                        type="button"
                        onClick={(e) => handleDeleteProject(proj.id, e)} 
                        className="absolute top-6 right-6 z-[60] w-12 h-12 flex items-center justify-center text-red-400 hover:text-red-100 bg-red-500/10 hover:bg-red-500 opacity-20 group-hover:opacity-100 transition-all duration-300 rounded-2xl cursor-pointer pointer-events-auto border border-red-500/20 shadow-xl"
                        title="Excluir Projeto Permanentemente"
                      >
                        <Trash2 size={24} strokeWidth={2.5} />
                      </button>

                      <div className="flex items-start justify-between relative z-[30]">
                        <div className="w-12 h-12 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5 group-hover:border-emerald-500/20"><Library size={20} className="text-zinc-600 group-hover:text-emerald-500" /></div>
                      </div>

                      <div className="space-y-3 relative z-10 pointer-events-none">
                        <div className="space-y-1">
                          <div className="flex items-center gap-1.5 text-emerald-500 mb-1"><UserCircle size={10} /><span className="text-[9px] font-black uppercase tracking-widest">{proj.client_name}</span></div>
                          <h3 className="text-base font-black text-white truncate">{proj.name}</h3>
                        </div>
                        <div className="flex flex-col gap-1.5 opacity-50">
                            <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Layers size={10} /> {proj.slideCount} Slides</div>
                            <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Clock size={10} /> {new Date(proj.updatedAt).toLocaleDateString()}</div>
                        </div>
                      </div>
                      <div className="flex items-center justify-end pt-4 border-t border-white/5 relative z-10 pointer-events-none"><ChevronRightSmall size={14} className="text-emerald-500 opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all" /></div>
                  </div>
                ))}
            </div>
            {filteredProjects.length === 0 && !isSyncing && (
              <div className="flex flex-col items-center justify-center py-40 text-zinc-600 gap-4 opacity-50">
                 <FolderHeart size={64} strokeWidth={1} />
                 <p className="font-black uppercase tracking-widest text-[10px]">Nenhum projeto encontrado</p>
              </div>
            )}
            {isSyncing && filteredProjects.length === 0 && (
               <div className="flex flex-col items-center justify-center py-40 text-emerald-500 gap-4 opacity-50">
                 <Loader2 size={48} className="animate-spin" />
                 <p className="font-black uppercase tracking-widest text-[10px]">Carregando projetos...</p>
              </div>
            )}
          </main>
        </div>
      ) : (
        <div className="flex h-screen w-full">
          {/* EDITOR ASIDE */}
          <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
            <header className="p-5 border-b border-white/5 space-y-4">
              <div className="flex items-center justify-between">
                <button onClick={() => setView('DASHBOARD')} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-zinc-500 hover:text-white transition-all"><Home size={18} /></button>
                <div className="flex items-center gap-2 text-center flex-1 justify-center">
                  <div className="w-6 h-6 bg-emerald-500 rounded-lg flex items-center justify-center shadow-lg"><LayoutTemplate size={14} className="text-black" /></div>
                  <h1 className="text-sm font-black text-white italic uppercase tracking-tighter">InstaRender</h1>
                </div>
                <button 
                   type="button"
                   onClick={() => setShowSaveModal(true)} 
                   className={`p-2 rounded-lg transition-all ${isSyncing ? 'bg-zinc-800 text-zinc-500' : 'bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400'}`}
                   disabled={isSyncing}
                >
                  {isSyncing ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                </button>
              </div>
              <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">
                {['TEMPLATES', 'DESIGN', 'ASSETS', 'TEXTURES', 'JSON'].map(tab => (
                  <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 px-1 rounded-lg text-[9px] font-black uppercase tracking-wider transition-all ${activeTab === tab ? 'bg-zinc-800 text-emerald-400 border border-white/5' : 'text-zinc-500 hover:text-zinc-300'}`}>
                    {tab === 'TEMPLATES' && <Library size={14} />}
                    {tab === 'DESIGN' && <Palette size={14} />}
                    {tab === 'ASSETS' && <ImageIcon size={14} />}
                    {tab === 'TEXTURES' && <Layers size={14} />}
                    {tab === 'JSON' && <FileJson size={14} />}
                    {tab.slice(0, 4)}
                  </button>
                ))}
              </nav>
            </header>
            <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-6">
              {activeTab === 'DESIGN' ? (
                <div className="space-y-10 animate-in fade-in slide-in-from-left-4 duration-300">
                  <section className="space-y-4">
                    <div className="flex items-center justify-between px-1">
                      <h3 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Brand Palettes</h3>
                      <button onClick={() => setIsCreatingPalette(true)} className="text-[8px] font-black text-emerald-400 uppercase flex items-center gap-1 hover:text-white transition-all bg-emerald-500/10 px-2.5 py-1.5 rounded-lg border border-emerald-500/20"><Plus size={10} strokeWidth={3} /> New Palette</button>
                    </div>
                    <div className="grid grid-cols-1 gap-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                      {brandPresets.map(preset => (
                        <button key={preset.id} onClick={() => handleApplyPalettePreset(preset)} className={`w-full p-4 border rounded-2xl transition-all flex items-center justify-between group ${activePaletteId === preset.id ? 'bg-emerald-500/10 border-emerald-500' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                          <div className="flex items-center gap-4">
                            <div className="flex -space-x-2">{preset.colors.slice(0, 4).map((c: string, i: number) => (<div key={i} className="w-5 h-5 rounded-full border-2 border-zinc-900 shadow-sm" style={{ backgroundColor: c }} />))}</div>
                            <span className={`text-[11px] font-black uppercase ${activePaletteId === preset.id ? 'text-emerald-400' : 'text-zinc-400'}`}>{preset.name}</span>
                          </div>
                          {!DEFAULT_BRAND_PRESETS.some(d => d.id === preset.id) && (<button onClick={(e) => handleDeletePalette(e, preset.id)} className="p-2 opacity-0 group-hover:opacity-100 hover:text-red-400 transition-all text-zinc-600"><Trash2 size={12} /></button>)}
                        </button>
                      ))}
                    </div>
                  </section>
                  <section className="space-y-6">
                    <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Edit3 size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Editor de Cores</h3></div>
                    <div className="grid grid-cols-1 gap-6">
                      <PaletteColorSelector label="Background" value={currentSlide?.options?.background || '#0D0D0D'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'background'], v)} />
                      <PaletteColorSelector label="Accent" value={currentSlide?.options?.accent || '#EAB308'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'accent'], v)} />
                      <PaletteColorSelector label="Text" value={currentSlide?.options?.text || '#FFFFFF'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'text'], v)} />
                      <PaletteColorSelector label="Cards" value={currentSlide?.options?.cardBg || currentSlide?.options?.accent || '#EAB308'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'cardBg'], v)} />
                    </div>
                  </section>
                </div>
              ) : activeTab === 'TEMPLATES' ? (
                <div className="grid grid-cols-1 gap-2.5 animate-in fade-in duration-300">
                   {templates.map(tpl => (
                      <button key={tpl.name} onClick={() => handleTemplateSelect(tpl)} className={`w-full p-4 text-left border rounded-xl transition-all flex items-center justify-between ${currentSlide?.template === tpl.name ? 'border-emerald-500/50 bg-emerald-500/5' : 'border-white/5 bg-white/5 hover:border-white/10'}`}>
                        <div><p className={`text-[10px] font-black uppercase mb-0.5 ${currentSlide?.template === tpl.name ? 'text-emerald-400' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[9px] text-zinc-500 opacity-60">{tpl.description}</p></div>
                      </button>
                    ))}
                </div>
              ) : activeTab === 'TEXTURES' ? (
                <div className="space-y-10 animate-in fade-in slide-in-from-left-4 duration-300">
                   <section className="space-y-4">
                      <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Layers size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Tipo de Ruído</h3></div>
                      <div className="grid grid-cols-2 gap-2">
                        {TEXTURE_PRESETS.map(preset => (
                          <button key={preset.id} onClick={() => updateSlideProperty(['options', 'texture', 'type'], preset.id)} className={`flex flex-col items-center gap-2 p-4 rounded-2xl border transition-all ${currentSlide?.options?.texture?.type === preset.id ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-zinc-300'}`}><preset.icon size={20} /><span className="text-[9px] font-black uppercase tracking-widest">{preset.label}</span></button>
                        ))}
                      </div>
                   </section>
                   <section className="space-y-6">
                      <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Wind size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Ajustes de Textura</h3></div>
                      <div className="space-y-8">
                        <TransformControl label="Intensidade (Opacidade)" value={currentSlide?.options?.texture?.amount ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateSlideProperty(['options', 'texture', 'amount'], v)} />
                        <div className="space-y-2.5">
                           <span className="text-[9px] font-black text-zinc-500 uppercase px-1 tracking-widest">Modo de Camada (Blend)</span>
                           <div className="grid grid-cols-2 gap-1.5 max-h-[200px] overflow-y-auto custom-scrollbar pr-1">{BLEND_MODES.map(mode => (<button key={mode} onClick={() => updateSlideProperty(['options', 'texture', 'blendMode'], mode)} className={`py-2 px-3 rounded-lg text-left text-[9px] font-black uppercase tracking-tighter border transition-all ${currentSlide?.options?.texture?.blendMode === mode ? 'bg-emerald-500 text-black border-emerald-500' : 'bg-black/40 border-white/5 text-zinc-500 hover:text-white'}`}>{mode}</button>))}</div>
                        </div>
                      </div>
                   </section>
                </div>
              ) : activeTab === 'ASSETS' ? (
                <div className="space-y-8 animate-in fade-in duration-300">
                  <div className={`p-4 border rounded-2xl transition-all ${isLocked ? 'opacity-50 pointer-events-none' : 'bg-white/5 border-white/10'}`}>
                    {imageConfig?.url ? (
                      <div className="space-y-6">
                        <div className="relative aspect-video rounded-xl overflow-hidden bg-zinc-900 border border-white/10 group">
                          <img src={imageConfig.url} className="w-full h-full object-contain" />
                          <button onClick={() => updateSlideProperty(['image', 'url'], undefined)} className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={12}/></button>
                        </div>
                        <div className="space-y-5">
                          <TransformControl label="Escala" value={imageConfig.scale ?? 1} min={0.1} max={5} step={0.05} onChange={(v) => updateSlideProperty(['image', 'scale'], v)} />
                          {currentSlide?.template === 'CINEMATIC_BG' && (<TransformControl label="Opacidade do Fundo" value={imageConfig.backgroundOpacity ?? 1} min={0} max={1} step={0.05} onChange={(v) => updateSlideProperty(['image', 'backgroundOpacity'], v)} />)}
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center h-48 border-2 border-dashed border-white/5 rounded-2xl hover:bg-white/5 transition-all relative">
                        <PlusCircle className="w-5 h-5 text-zinc-500 mb-2" /><p className="text-[10px] font-black uppercase text-zinc-400">Upload de Imagem</p><input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleImageUpload} disabled={isLocked} />
                      </div>
                    )}
                  </div>
                  <div className="px-1 py-4 bg-zinc-800/20 border border-zinc-700/30 rounded-2xl flex flex-col items-center gap-3"><ClipboardPaste size={20} className="text-zinc-600" /><p className="text-[10px] font-black uppercase text-zinc-500 text-center px-4">Use CTRL+V no editor para colar imagens rapidamente!</p></div>
                </div>
              ) : activeTab === 'JSON' ? (
                <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[500px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-xl outline-none" spellCheck={false} />
              ) : null}
            </div>
            <footer className="p-5 border-t border-white/5 bg-zinc-950 flex gap-3">
              <button disabled={!carousel || isExporting} onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="flex-1 py-4 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-30 text-black font-black rounded-xl text-[10px] uppercase transition-all shadow-lg flex items-center justify-center gap-3 active:scale-95"><Download size={16} strokeWidth={3} /> Exportar</button>
            </footer>
          </aside>

          {/* CANVAS AREA */}
          <main className="flex-1 bg-[#18181b] relative flex flex-col">
            {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-top-4 duration-300"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">{error}</span></div>}
            <div className="absolute top-5 right-5 z-40 flex items-center gap-0.5 bg-black/30 backdrop-blur-xl p-1 rounded-xl border border-white/5 opacity-60 hover:opacity-100 transition-opacity">
              <button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomOut size={16} /></button>
              <div className="px-2 text-[9px] font-black font-mono text-zinc-400 w-10 text-center">{(zoom * 100).toFixed(0)}%</div>
              <button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomIn size={16} /></button>
            </div>
            <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar p-10" onMouseUp={handleCanvasMouseUp}>
              <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">
                {carousel?.slides?.[currentIndex] ? <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(block, blockIdx) => setEditingIconBlock({ block, index: blockIdx })} /> : <div className="opacity-10"><Loader2 className="w-10 h-10 animate-spin text-emerald-500" /></div>}
              </div>
            </div>
            {carousel && carousel.slides.length > 0 && (
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-8 bg-black/40 backdrop-blur-xl px-8 py-4 rounded-[32px] border border-white/5 shadow-2xl transition-opacity hover:opacity-100 opacity-90">
                 <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20} strokeWidth={3}/></button>
                 <div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-emerald-500 shadow-lg shadow-emerald-500/30' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div>
                 <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20} strokeWidth={3}/></button>
              </div>
            )}
          </main>
        </div>
      )}
    </div>
  );
};

export default App;

