      // Atualizar LocalStorage
      const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
      const index = existing.findIndex((p: any) => p.id === savedId);
      const updated = index >= 0 ? existing.map((p: any) => p.id === savedId ? projectObj : p) : [projectObj, ...existing];
