const FloatingTextToolbar = ({ 
  state, 
  onClose, 
  onUpdate 
}: { 
  state: ToolbarState, 
  onClose: () => void, 
  onUpdate: (updates: { path: (string | number)[], value: any }[]) => void 
}) => {
  const [localFontSize, setLocalFontSize] = useState(state.options?.fontSize || 40);
  const [localSpacing, setLocalSpacing] = useState(state.options?.letterSpacing || 0);
  const [localLineHeight, setLocalLineHeight] = useState(state.options?.lineHeight || 1.2);
  const [localColor, setLocalColor] = useState(state.options?.color || '#ffffff');

  const [pos, setPos] = useState({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const toolbarRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setLocalFontSize(state.options?.fontSize || 40);
    setLocalSpacing(state.options?.letterSpacing || 0);
    setLocalLineHeight(state.options?.lineHeight || 1.2);
    setLocalColor(state.options?.color || '#ffffff');
    setPos({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  }, [state]);

  const onMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    dragStart.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
    e.stopPropagation();
  };

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      setPos({ x: e.clientX - dragStart.current.x, y: e.clientY - dragStart.current.y });
    };
    const onMouseUp = () => setIsDragging(false);
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [isDragging]);

  const update = (key: string, val: any) => {
    onUpdate([{ path: ['blocks', state.blockIndex, 'options', key], value: val }]);
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (toolbarRef.current && !toolbarRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    const timeout = setTimeout(() => {
      document.addEventListener('mousedown', handleClickOutside);
    }, 100);
    return () => {
      clearTimeout(timeout);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [onClose]);

  return (
    <div 
      ref={toolbarRef}
      className="fixed z-[1000] bg-zinc-900/95 backdrop-blur-xl border border-white/10 rounded-[28px] shadow-2xl p-6 flex flex-col gap-6 w-80 animate-in zoom-in-95 duration-200 floating-toolbar select-none"
      style={{ top: `${pos.y}px`, left: `${pos.x}px` }}
      onClick={(e) => e.stopPropagation()}
    >
      <div 
        className="flex items-center justify-between cursor-move pb-2 border-b border-white/5 -mt-2"
        onMouseDown={onMouseDown}
      >
        <div className="flex items-center gap-2">
           <GripHorizontal size={14} className="text-zinc-600" />
           <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest">{state.blockType} Editor</span>
        </div>
        <button onClick={onClose} className="p-1 hover:bg-white/5 rounded-full text-zinc-500 hover:text-white"><X size={14}/></button>
      </div>

      <div className="grid grid-cols-1 gap-5">
        <div className="flex gap-4 items-end">
          <div className="flex-1 space-y-1">
             <TransformControl label="Font Size" value={localFontSize} min={10} max={400} step={1} onChange={(v) => { setLocalFontSize(v); update('fontSize', v); }} />
          </div>
          <div className="relative w-12 h-12 rounded-xl overflow-hidden border border-white/10 shadow-inner shrink-0">
             <input type="color" value={localColor} onChange={(e) => { setLocalColor(e.target.value); update('color', e.target.value); }} className="absolute inset-[-4px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none" />
          </div>
        </div>

        <div className="flex gap-4">
          <TransformControl label="Letter Spacing" value={localSpacing} min={-20} max={50} step={1} onChange={(v) => { setLocalSpacing(v); update('letterSpacing', v); }} />
          <TransformControl label="Line Height" value={localLineHeight} min={0.5} max={3.0} step={0.05} onChange={(v) => { setLocalLineHeight(v); update('lineHeight', v); }} />
        </div>

        <div className="space-y-1.5">
           <span className="text-[9px] font-bold text-zinc-500 uppercase px-1">Alignment</span>
           <div className="flex bg-black/40 p-1 rounded-xl border border-white/5 gap-1">
              {[
                { id: 'left', icon: AlignLeft },
                { id: 'center', icon: AlignCenter },
                { id: 'right', icon: AlignRight }
              ].map(align => (
                <button 
                  key={align.id} 
                  onClick={() => update('textAlign', align.id)}
                  className={`flex-1 py-2 flex items-center justify-center rounded-lg transition-all ${state.options?.textAlign === align.id ? 'bg-zinc-800 text-emerald-400' : 'text-zinc-500 hover:text-white'}`}
                >
                  <align.icon size={16} />
                </button>
              ))}
           </div>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [view, setView] = useState<'DASHBOARD' | 'EDITOR'>('DASHBOARD');
  const [activeTab, setActiveTab] = useState<'TEMPLATES' | 'DESIGN' | 'TEXTURES' | 'ASSETS' | 'JSON'>('TEMPLATES');

  const [projects, setProjects] = useState<Project[]>([]);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedClientFilter, setSelectedClientFilter] = useState<string | null>(null);

  const [dslInput, setDslInput] = useState(INITIAL_DSL);
  const [carousel, setCarousel] = useState<ValidatedCarousel | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [zoom, setZoom] = useState(0.40);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);
  const [isLocalMode, setIsLocalMode] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const [activePaletteId, setActivePaletteId] = useState('1');
  const [brandPresets, setBrandPresets] = useState<any[]>(DEFAULT_BRAND_PRESETS);
  const [isCreatingPalette, setIsCreatingPalette] = useState(false);
  const [newPaletteData, setNewPaletteData] = useState({
    name: '',
    colors: ['#0D0D0D', '#FFFFFF', '#EAB308', '#EAB308', '#EAB308']
  });

  const [toolbarState, setToolbarState] = useState<ToolbarState | null>(null);
  const [showExportModal, setShowExportModal] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [saveFormData, setSaveFormData] = useState({ name: '', client: '' });
  const [selectedSlidesToExport, setSelectedSlidesToExport] = useState<Set<number>>(new Set());

  const [isExporting, setIsExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [exportStatus, setExportStatus] = useState('');

  const [templates] = useState<TemplateDefinition[]>(templateRegistry.getAll());
  const [editingIconBlock, setEditingIconBlock] = useState<{ block: Block; index: number } | null>(null);
  const [iconInput, setIconInput] = useState('');

  const canvasRef = useRef<HTMLDivElement>(null);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  // CARREGAMENTO INSTANTÂNEO
  const loadData = useCallback(async () => {
    // 1. LocalStorage primeiro
    const localProjects = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
    const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');

    if (localProjects.length > 0) setProjects(localProjects);
    if (localPalettes.length > 0) setBrandPresets([...DEFAULT_BRAND_PRESETS, ...localPalettes]);

    // 2. Supabase em background
    setIsSyncing(true);
    try {
      const { data: projData, error: projError } = await supabase
        .from('projects')
        .select('*')
        .order('updated_at', { ascending: false });

      if (projError) throw projError;

      const loadedProjects = projData.map(p => ({
        id: p.id,
        name: p.name,
        client_name: p.client_name,
        updatedAt: new Date(p.updated_at).getTime(),
        data: p.data,
        slideCount: p.slide_count
      }));

      setProjects(loadedProjects);
      localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(loadedProjects));
      setIsLocalMode(false);
    } catch (err: any) {
      console.warn("Supabase Sync Failed. Modo Offline.");
      setIsLocalMode(true);
    } finally {
      setIsSyncing(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // EXCLUSÃO SEGURA
  const handleDeleteProject = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation(); 

    if (!window.confirm("Deseja realmente excluir este projeto?")) return;

    setDeletingId(id);
    try {
      // Remover local
      const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
      const updated = existing.filter((p: any) => p.id !== id);
      localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(updated));
      setProjects(updated);

      // Remover servidor
      if (!id.toString().startsWith('local_') && !isLocalMode) {
        await supabase.from('projects').delete().eq('id', id);
      }

      if (currentProjectId === id) handleNewProject();
      showToast("Projeto excluído.");
    } catch (err: any) {
      showToast("Excluído apenas localmente.", "error");
    } finally {
      setDeletingId(null);
    }
  };

  const updateSlideProperties = useCallback((updates: { path: (string | number)[], value: any }[]) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        if (!parsed.slides[currentIndex]) return prev;
        updates.forEach(({ path, value }) => {
          let target = parsed.slides[currentIndex];
          for (let i = 0; i < path.length - 1; i++) {
            const key = path[i];
            if (!target[key] || typeof target[key] !== 'object') target[key] = {};
            target = target[key];
          }
          target[path[path.length - 1]] = value;
        });
        return JSON.stringify(parsed, null, 2);
      } catch (e) { return prev; }
    });
  }, [currentIndex]);

  const updateSlideProperty = useCallback((path: (string | number)[], value: any) => {
    updateSlideProperties([{ path, value }]);
  }, [updateSlideProperties]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => updateSlideProperty(['image', 'url'], reader.result as string);
    reader.readAsDataURL(file);
  };

  const handleRender = useCallback(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) {
        setCarousel(result.data);
        setError(null);
      } else {
        setError(result.error.errors.map(e => `[${e.path.join(' → ')}]: ${e.message}`).join('\n'));
      }
    } catch (e: any) { setError(`Sintaxe: ${e.message}`); }
  }, [dslInput]);

  useEffect(() => { handleRender(); }, [handleRender]);

  const handleNewProject = () => {
    setDslInput(INITIAL_DSL);
    setCurrentProjectId(null);
    setCurrentIndex(0);
    setSaveFormData({ name: '', client: '' });
    setView('EDITOR');
  };

  const handleOpenProject = (proj: Project) => {
    setDslInput(proj.data);
    setCurrentProjectId(proj.id);
    setSaveFormData({ name: proj.name, client: proj.client_name });
    setCurrentIndex(0);
    setView('EDITOR');
  };

  const handleSaveToSupabase = async () => {
    if (!saveFormData.name.trim()) return;
    setIsSyncing(true);
    const now = new Date().toISOString();
    const payload = {
      name: saveFormData.name,
      client_name: saveFormData.client || 'Geral',
      data: dslInput,
      slide_count: carousel?.slides.length || 0,
      updated_at: now
    };

    try {
      let savedId = currentProjectId;
      if (!isLocalMode) {
        let res;
        if (currentProjectId && !currentProjectId.startsWith('local_')) {
          res = await supabase.from('projects').update(payload).eq('id', currentProjectId).select();
        } else {
          res = await supabase.from('projects').insert([payload]).select();
        }
        if (res.error) throw res.error;
        if (res.data?.[0]) savedId = res.data[0].id;
      } else {
        savedId = currentProjectId || `local_${Date.now()}`;
      }

      const projectObj = {
        id: savedId!,
        name: payload.name,
        client_name: payload.client_name,
        updatedAt: Date.now(),
        data: payload.data,
        slideCount: payload.slide_count
      };

      const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
      const index = existing.findIndex((p: any) => p.id === savedId);
      const updated = index >= 0 ? existing.map((p: any) => p.id === savedId ? projectObj : p) : [projectObj, ...existing];
      localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(updated));
      setProjects(updated);
      setCurrentProjectId(savedId);

      setShowSaveModal(false);
      showToast(isLocalMode ? "Salvo Offline" : "Salvo no Servidor");
    } catch (err: any) {
      showToast("Erro ao salvar.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const filteredProjects = useMemo(() => {
    return projects.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || p.client_name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesClient = selectedClientFilter ? p.client_name === selectedClientFilter : true;
      return matchesSearch && matchesClient;
    });
  }, [projects, searchQuery, selectedClientFilter]);

  const clients = useMemo(() => Array.from(new Set(projects.map(p => p.client_name))).sort(), [projects]);

  const handleCanvasMouseUp = (e: React.MouseEvent) => {
    const selection = window.getSelection();
    if (!selection || selection.isCollapsed) return;
    const range = selection.getRangeAt(0);
    const rect = range.getBoundingClientRect();
    const targetBlock = (e.target as HTMLElement).closest('[data-block-index]');
    if (targetBlock) {
       const bIndex = parseInt(targetBlock.getAttribute('data-block-index') || '0', 10);
       const bType = targetBlock.querySelector('[data-block-type]')?.getAttribute('data-block-type') || 'Block';
       const currentBlock = carousel?.slides?.[currentIndex]?.blocks?.[bIndex];
       if (currentBlock) {
          setToolbarState({
            x: Number(rect.left) + Number(rect.width) / 2,
            y: Number(rect.top),
            blockIndex: bIndex,
            blockType: bType,
            options: currentBlock.options || {}
          });
       }
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden">

      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-2xl backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-emerald-500/95 text-black' : 'bg-red-500/95 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} /> : <AlertCircle size={28} />}
          <span className="text-[16px] font-black uppercase tracking-[0.1em]">{toast.message}</span>
        </div>
      )}

      {toolbarState && (
        <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />
      )}

      {view === 'DASHBOARD' ? (
        <div className="min-h-screen w-full bg-[#050507] text-white flex flex-col overflow-y-auto custom-scrollbar">
          <header className="px-10 py-8 flex items-center justify-between border-b border-white/5 sticky top-0 bg-[#050507]/80 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center shadow-2xl shadow-emerald-500/20"><LayoutTemplate size={20} className="text-black" /></div>
              <h1 className="text-xl font-black italic uppercase tracking-tighter">Insta<span className="text-emerald-500">Render</span></h1>
              {isSyncing && <Loader2 size={14} className="animate-spin text-zinc-500" />}
            </div>
            <div className="flex-1 max-w-xl mx-20 relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={18} />
              <input type="text" placeholder="Pesquisar projetos..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 text-[13px] font-bold text-white outline-none focus:border-emerald-500/50 transition-all" />
            </div>
            <button onClick={handleNewProject} className="flex items-center gap-2 px-6 py-3 bg-emerald-500 text-black font-black uppercase text-[11px] rounded-xl hover:bg-emerald-400 transition-all shadow-xl active:scale-95"><Plus size={16} strokeWidth={3} /> Criar Projeto</button>
          </header>

          <main className="p-10 max-w-[1400px] mx-auto w-full">
            <div className="mb-12 flex flex-col gap-6">
                <div className="flex items-center gap-3 text-zinc-400 mb-2">
                  <Filter size={18} className="text-emerald-500" />
                  <h2 className="text-[10px] font-black uppercase tracking-[0.2em]">Clientes</h2>
                </div>
                <div className="flex gap-2 flex-wrap">
                  <button onClick={() => setSelectedClientFilter(null)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${!selectedClientFilter ? 'bg-emerald-500 text-black border-emerald-500 shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>Todos</button>
                  {clients.map(client => (
                    <button key={client} onClick={() => setSelectedClientFilter(client)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedClientFilter === client ? 'bg-emerald-500 text-black border-emerald-500 shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>{client}</button>
                  ))}
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProjects.map(proj => (
                  <div key={proj.id} className="relative h-80 bg-zinc-900/40 border border-white/5 rounded-[32px] flex flex-col transition-all group overflow-hidden hover:border-emerald-500/30">

                      <div className="absolute top-4 right-4 z-[100]">
                         <button 
                            type="button"
                            disabled={deletingId === proj.id}
                            onClick={(e) => handleDeleteProject(proj.id, e)}
                            className={`w-12 h-12 flex items-center justify-center rounded-2xl transition-all duration-300 shadow-xl ${deletingId === proj.id ? 'bg-zinc-800 text-zinc-600' : 'bg-red-500/10 hover:bg-red-500 text-red-500 hover:text-white opacity-20 group-hover:opacity-100 border border-red-500/20'}`}
                         >
                            {deletingId === proj.id ? <Loader2 size={20} className="animate-spin" /> : <Trash2 size={22} />}
                         </button>
                      </div>

                      <div onClick={() => handleOpenProject(proj)} className="flex-1 p-8 space-y-4 cursor-pointer hover:bg-white/5 transition-colors">
                        <div className="w-12 h-12 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5"><Library size={20} className="text-zinc-600 group-hover:text-emerald-500" /></div>

                        <div className="space-y-3 pointer-events-none">
                          <div className="space-y-1">
                            <div className="flex items-center gap-1.5 text-emerald-500 mb-1 font-black uppercase tracking-widest text-[9px]"><UserCircle size={10} />{proj.client_name}</div>
                            <h3 className="text-base font-black text-white truncate">{proj.name}</h3>
                          </div>
                          <div className="flex flex-col gap-1.5 opacity-40">
                              <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Layers size={10} /> {proj.slideCount} Slides</div>
                              <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Clock size={10} /> {new Date(proj.updatedAt).toLocaleDateString()}</div>
                          </div>
                        </div>
                      </div>

                      <div className="h-14 px-8 flex items-center justify-end pointer-events-none opacity-20 group-hover:opacity-100 transition-opacity">
                         <ChevronRight size={20} className="text-emerald-500" />
                      </div>
                  </div>
                ))}
            </div>
          </main>
        </div>
      ) : (
        <div className="flex h-screen w-full">
           <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
             <header className="p-5 border-b border-white/5 space-y-4">
              <div className="flex items-center justify-between">
                <button onClick={() => setView('DASHBOARD')} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-zinc-500 hover:text-white transition-all"><Home size={18} /></button>
                <div className="flex items-center gap-2 text-center flex-1 justify-center">
                  <div className="w-6 h-6 bg-emerald-500 rounded-lg flex items-center justify-center shadow-lg"><LayoutTemplate size={14} className="text-black" /></div>
                  <h1 className="text-sm font-black text-white italic uppercase tracking-tighter">InstaRender</h1>
                </div>
                <button 
                   type="button"
                   onClick={() => setShowSaveModal(true)} 
                   className={`p-2 rounded-lg transition-all ${isSyncing ? 'bg-zinc-800 text-zinc-500' : 'bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400'}`}
                   disabled={isSyncing}
                >
                  {isSyncing ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                </button>
              </div>
              <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">
                {['TEMPLATES', 'DESIGN', 'ASSETS', 'TEXTURES', 'JSON'].map(tab => (
                  <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 px-1 rounded-lg text-[9px] font-black uppercase tracking-wider transition-all ${activeTab === tab ? 'bg-zinc-800 text-emerald-400 border border-white/5' : 'text-zinc-500 hover:text-zinc-300'}`}>
                    {tab === 'TEMPLATES' && <Library size={14} />}
                    {tab === 'DESIGN' && <Palette size={14} />}
                    {tab === 'ASSETS' && <ImageIcon size={14} />}
                    {tab === 'TEXTURES' && <Layers size={14} />}
                    {tab === 'JSON' && <FileJson size={14} />}
                    {tab.slice(0, 4)}
                  </button>
                ))}
              </nav>
            </header>
            <div className="flex-1 overflow-y-auto custom-scrollbar p-5">
               {activeTab === 'TEMPLATES' && (
                 <div className="grid grid-cols-1 gap-2.5 animate-in fade-in duration-300">
                    {templates.map(tpl => (
                       <button key={tpl.name} onClick={() => { updateSlideProperty(['template'], tpl.name); }} className={`w-full p-4 text-left border rounded-xl transition-all flex items-center justify-between ${carousel?.slides[currentIndex]?.template === tpl.name ? 'border-emerald-500/50 bg-emerald-500/5' : 'border-white/5 bg-white/5 hover:border-white/10'}`}>
                         <div><p className={`text-[10px] font-black uppercase mb-0.5 ${carousel?.slides[currentIndex]?.template === tpl.name ? 'text-emerald-400' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[9px] text-zinc-500 opacity-60">{tpl.description}</p></div>
                       </button>
                     ))}
                 </div>
               )}
               {activeTab === 'JSON' && (
                 <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[500px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-xl outline-none" spellCheck={false} />
               )}
            </div>
            <footer className="p-5 border-t border-white/5 bg-zinc-950 flex gap-3">
              <button disabled={!carousel} onClick={() => setShowExportModal(true)} className="flex-1 py-4 bg-emerald-500 hover:bg-emerald-400 text-black font-black rounded-xl text-[10px] uppercase transition-all flex items-center justify-center gap-3"><Download size={16} /> Exportar</button>
            </footer>
           </aside>

           <main className="flex-1 bg-[#18181b] relative flex flex-col">
              <div className="flex-1 flex items-center justify-center overflow-auto custom-scrollbar p-10" onMouseUp={handleCanvasMouseUp}>
                <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-2xl shrink-0">
                  {carousel?.slides?.[currentIndex] && <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} />}
                </div>
              </div>
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-8 bg-black/40 backdrop-blur-xl px-8 py-4 rounded-[32px] border border-white/5 shadow-2xl">
                 <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20}/></button>
                 <div className="flex gap-2.5">{carousel?.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 rounded-full transition-all ${currentIndex === i ? 'w-8 bg-emerald-500' : 'w-2 bg-white/10'}`} />))}</div>
                 <button disabled={currentIndex === (carousel?.slides.length || 1) - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20}/></button>
              </div>
           </main>
        </div>
      )}

      {showSaveModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowSaveModal(false)}>
           <div className="w-full max-w-md bg-zinc-900 border border-white/10 rounded-[32px] p-8 space-y-8 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <h2 className="text-lg font-black text-white uppercase tracking-tight">Salvar Projeto</h2>
                 <button onClick={() => setShowSaveModal(false)} className="p-2 hover:bg-white/5 rounded-full"><X size={24}/></button>
              </div>
              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Nome do Projeto</label>
                  <input type="text" value={saveFormData.name} onChange={(e) => setSaveFormData({ ...saveFormData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none" placeholder="Ex: Campanha Verão" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Cliente</label>
                  <input type="text" list="client-datalist" value={saveFormData.client} onChange={(e) => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none" placeholder="Ex: Coca-Cola" />
                  <datalist id="client-datalist">{clients.map(c => <option key={c} value={c} />)}</datalist>
                </div>
              </div>
              <button type="button" onClick={handleSaveToSupabase} disabled={isSyncing || !saveFormData.name.trim()} className="w-full py-5 bg-emerald-500 text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3 transition-all active:scale-95">
                {isSyncing ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                Salvar Agora
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type BlockType = 'TITLE' | 'LIST' | 'IMAGE' | 'SPACER' | 'PARAGRAPH' | 'CARD' | 'BADGE' | 'BOX';

export interface Block {
  type: BlockType;
  content?: string | string[];
  options?: {
    highlight?: string;
    variant?: 'default' | 'accent' | 'muted' | 'box' | 'ghost' | 'outlined';
    size?: 'sm' | 'md' | 'lg';
    icon?: string;
    customIcon?: string; // URL da imagem ou string SVG
    align?: 'left' | 'center' | 'right';
    // Text styling overrides
    fontSize?: number;
    color?: string;
    letterSpacing?: number;
    lineHeight?: number;
    textAlign?: 'left' | 'center' | 'right';
  };
}

export interface Project {
  id: string;
  name: string;
  client_name: string;
  updatedAt: number;
  data: string; // JSON string do carrossel
  slideCount: number;
}

export type LayoutType = 'CENTERED' | 'STACKED' | 'SPLIT_IMAGE_TOP' | 'SPLIT_IMAGE_SIDE' | 'EDITORIAL' | 'GRID';

export interface TemplateDefinition {
  name: string;
  description: string;
  layoutType: LayoutType;
  allowedBlocks: BlockType[];
  maxBlocks?: number;
}

export interface SlideImageConfig {
  type: 'IMAGE_SELECT' | 'IMAGE_BACKGROUND' | 'IMAGE_BOX' | 'FOCUS_SUBJECT' | 'IMAGE_GLASS_CARD' | 'IMAGE_SPLIT_HALF' | 'NONE';
  url?: string;
  overlay?: 'dark' | 'blur-card' | 'none';
  boxOverlay?: 'dark' | 'light';
  position?: 'right' | 'left';
  format?: 'png' | 'jpg';
  scale?: number;
  x?: number;
  y?: number;
  width?: number;
  backgroundOpacity?: number;
  // Visual Styles
  borderWidth?: number;
  borderColor?: string;
  hasShadow?: boolean;
}

export interface SlideDefinition {
  template: string;
  image?: SlideImageConfig;
  options?: {
    theme?: 'dark' | 'light';
    background?: string;
    accent?: string;
    text?: string;
    cardBg?: string;
    backgroundImage?: string;
    texture?: {
      type: 'grain' | 'paper' | 'dust' | 'none';
      amount: number;
      blendMode?: string;
    };
  };
  blocks: Block[];
}

export interface CarouselDefinition {
  slides: SlideDefinition[];
}

export interface Theme {
  name: string;
  typography: {
    fontFamily: string;
    hero: string;
    title: string;
    paragraph: string;
    body: string;
    small: string;
    titleWeight: string | number;
