  colors: {
    background: string;
    textPrimary: string;
    textSecondary: string;
    accent: string;
    muted: string;
    highlight: string;
    cardBg?: string;
  };
  spacing: {
    canvasPadding: string;
    blockGap: string;
    sectionGap: string;
  };
  backgrounds: Record<string, any>;
}

