    <div 
      ref={toolbarRef}
      className="fixed z-[1000] bg-zinc-900/95 backdrop-blur-xl border border-white/10 rounded-[28px] shadow-2xl p-6 flex flex-col gap-6 w-80 animate-in zoom-in-95 duration-200 select-none"
      style={{ top: `${pos.y}px`, left: `${pos.x}px` }}
      onClick={(e) => e.stopPropagation()}
    >
      <div className="flex items-center justify-between cursor-default pb-2 border-b border-white/5 -mt-2">
        <div className="flex items-center gap-2">
           <GripHorizontal size={14} className="text-zinc-600" />
           <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest">{state.blockType} Editor</span>
        </div>
        <button onClick={onClose} className="p-1 hover:bg-white/5 rounded-full text-zinc-500 hover:text-white"><X size={14}/></button>
      </div>
      <div className="text-[10px] text-zinc-400">Opções de estilo para este bloco...</div>
    </div>
  );
};

const App: React.FC = () => {
  const [view, setView] = useState<'DASHBOARD' | 'EDITOR'>('DASHBOARD');
  const [activeTab, setActiveTab] = useState<'TEMPLATES' | 'DESIGN' | 'TEXTURES' | 'ASSETS' | 'JSON'>('TEMPLATES');
  const [projects, setProjects] = useState<Project[]>(() => {
    const local = localStorage.getItem(STORAGE_KEYS.PROJECTS);
    return local ? JSON.parse(local) : [];
  });

  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedClientFilter, setSelectedClientFilter] = useState<string | null>(null);
  const [dslInput, setDslInput] = useState(INITIAL_DSL);
  const [carousel, setCarousel] = useState<ValidatedCarousel | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [zoom, setZoom] = useState(0.40);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [toolbarState, setToolbarState] = useState<ToolbarState | null>(null);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [saveFormData, setSaveFormData] = useState({ name: '', client: '' });
  const [templates] = useState<TemplateDefinition[]>(templateRegistry.getAll());
  const canvasRef = useRef<HTMLDivElement>(null);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  const syncWithSupabase = useCallback(async () => {
    setIsSyncing(true);
    try {
      const { data, error } = await supabase.from('projects').select('*').order('updated_at', { ascending: false });
      if (error) throw error;
      const loaded = data.map(p => ({
        id: p.id,
        name: p.name,
        client_name: p.client_name,
        updatedAt: new Date(p.updated_at).getTime(),
        data: p.data,
        slideCount: p.slide_count
      }));
      setProjects(loaded);
      localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(loaded));
    } catch (err) {
      console.warn("Sync background falhou.");
    } finally {
      setIsSyncing(false);
    }
  }, []);

  useEffect(() => { syncWithSupabase(); }, [syncWithSupabase]);

  const handleDeleteProject = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation(); 
    if (!window.confirm("Excluir projeto permanentemente?")) return;

    // Ação Otimista: Remove da UI e do cache local imediatamente
    const updatedProjects = projects.filter(p => p.id !== id);
    setProjects(updatedProjects);
    localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(updatedProjects));

    setDeletingId(id);
    try {
      const { error } = await supabase.from('projects').delete().eq('id', id);
      if (error) throw error;
      showToast("Projeto removido do servidor.");
    } catch (err) {
      showToast("Removido apenas localmente.", "error");
    } finally {
      setDeletingId(null);
    }
  };

  // Fix: Added handleOpenProject to correctly load a project into the editor view
  const handleOpenProject = (proj: Project) => {
    setCurrentProjectId(proj.id);
    setDslInput(proj.data);
    setSaveFormData({ name: proj.name, client: proj.client_name });
    setView('EDITOR');
    setCurrentIndex(0);
  };

  const handleSaveToSupabase = async () => {
    if (!saveFormData.name.trim()) return;
    setIsSyncing(true);
    const payload = {
      name: saveFormData.name,
      client_name: saveFormData.client || 'Geral',
      data: dslInput,
      slide_count: carousel?.slides.length || 0,
      updated_at: new Date().toISOString()
    };

    try {
      let res;
      if (currentProjectId) {
        res = await supabase.from('projects').update(payload).eq('id', currentProjectId).select();
      } else {
        res = await supabase.from('projects').insert([payload]).select();
      }
      if (res.error) throw res.error;

      const saved = res.data[0];
      const newProj: Project = {
        id: saved.id,
        name: saved.name,
        client_name: saved.client_name,
        updatedAt: new Date(saved.updated_at).getTime(),
        data: saved.data,
        slideCount: saved.slide_count
      };

      const nextProjects = [newProj, ...projects.filter(p => p.id !== saved.id)];
      setProjects(nextProjects);
      localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(nextProjects));
      setCurrentProjectId(saved.id);
      setShowSaveModal(false);
      showToast("Projeto salvo!");
    } catch (err) {
      showToast("Erro ao salvar.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleRender = useCallback(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) {
        setCarousel(result.data);
        setError(null);
      } else {
        setError("Erro no DSL");
      }
    } catch (e) { setError("Sintaxe inválida"); }
  }, [dslInput]);

  useEffect(() => { handleRender(); }, [handleRender]);

  const filteredProjects = useMemo(() => {
    return projects.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesClient = selectedClientFilter ? p.client_name === selectedClientFilter : true;
      return matchesSearch && matchesClient;
    });
  }, [projects, searchQuery, selectedClientFilter]);

  const clients = useMemo(() => Array.from(new Set(projects.map(p => p.client_name))).sort(), [projects]);

  return (
    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden">
      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-8 py-4 rounded-2xl flex items-center gap-4 bg-emerald-500 text-black shadow-2xl animate-in slide-in-from-bottom-4`}>
          <CheckCircle size={20} />
          <span className="text-xs font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      {toolbarState && (
        <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={() => {}} />
      )}

      {view === 'DASHBOARD' ? (
        <div className="w-full flex flex-col overflow-y-auto custom-scrollbar">
          <header className="px-10 py-8 flex items-center justify-between border-b border-white/5 sticky top-0 bg-[#050507]/90 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center"><LayoutTemplate size={20} className="text-black" /></div>
              <h1 className="text-xl font-black italic uppercase">InstaRender</h1>
              {isSyncing && <Loader2 size={14} className="animate-spin text-zinc-600" />}
            </div>
            <div className="flex-1 max-w-md mx-10 relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={16} />
              <input 
                type="text" 
                placeholder="Pesquisar..." 
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-xl py-2.5 pl-12 pr-4 text-xs font-bold outline-none focus:border-emerald-500/50" 
              />
            </div>
            <button onClick={() => { setView('EDITOR'); setCurrentProjectId(null); setDslInput(INITIAL_DSL); }} className="flex items-center gap-2 px-6 py-2.5 bg-emerald-500 text-black font-black uppercase text-[10px] rounded-lg hover:bg-emerald-400">
              <Plus size={14} /> Novo Projeto
            </button>
          </header>

          <main className="p-10 max-w-7xl mx-auto w-full">
            <div className="mb-10 flex gap-2 overflow-x-auto pb-4 no-scrollbar">
              <button onClick={() => setSelectedClientFilter(null)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${!selectedClientFilter ? 'bg-emerald-500 text-black' : 'bg-white/5 text-zinc-500'}`}>Todos</button>
              {clients.map(c => (
                <button key={c} onClick={() => setSelectedClientFilter(c)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${selectedClientFilter === c ? 'bg-emerald-500 text-black' : 'bg-white/5 text-zinc-500'}`}>{c}</button>
              ))}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredProjects.map(proj => (
                <div key={proj.id} className="group relative bg-zinc-900/50 border border-white/5 rounded-3xl overflow-hidden hover:border-emerald-500/30 transition-all">
                  <div className="absolute top-4 right-4 z-20">
                    <button 
                      onClick={(e) => handleDeleteProject(proj.id, e)}
                      className="w-10 h-10 flex items-center justify-center rounded-xl bg-red-500/10 text-red-500 opacity-0 group-hover:opacity-100 hover:bg-red-500 hover:text-white transition-all"
                    >
                      {deletingId === proj.id ? <Loader2 size={16} className="animate-spin" /> : <Trash2 size={18} />}
                    </button>
                  </div>
                  <div onClick={() => handleOpenProject(proj)} className="p-6 cursor-pointer space-y-4">
                    <div className="w-12 h-12 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5"><Library size={20} className="text-zinc-600 group-hover:text-emerald-500" /></div>
                    <div>
                      <div className="text-[9px] font-black text-emerald-500 uppercase tracking-widest mb-1">{proj.client_name}</div>
                      <h3 className="text-sm font-bold text-white truncate">{proj.name}</h3>
                    </div>
                    <div className="flex items-center gap-4 text-[9px] text-zinc-600 font-bold uppercase">
                      <span className="flex items-center gap-1.5"><Layers size={10} /> {proj.slideCount} Slides</span>
                      <span className="flex items-center gap-1.5"><Clock size={10} /> {new Date(proj.updatedAt).toLocaleDateString()}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </main>
        </div>
      ) : (
        <div className="flex w-full h-full">
          <aside className="w-96 border-r border-white/5 flex flex-col bg-zinc-900/40 backdrop-blur-xl">
            <header className="p-5 border-b border-white/5 flex items-center justify-between">
              <button onClick={() => setView('DASHBOARD')} className="p-2 hover:bg-white/5 rounded-lg transition-all"><Home size={18} /></button>
              <div className="flex gap-2">
                <button onClick={() => setShowSaveModal(true)} className="p-2 bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 rounded-lg"><Save size={18}/></button>
              </div>
            </header>
            <div className="flex-1 p-5 overflow-y-auto custom-scrollbar">
              <textarea 
                value={dslInput} 
                onChange={e => setDslInput(e.target.value)}
                className="w-full h-full bg-transparent font-mono text-[10px] outline-none resize-none"
              />
            </div>
          </aside>
          <main className="flex-1 bg-[#121214] flex flex-col relative">
             <div className="absolute top-5 right-5 z-40 flex gap-2 bg-black/40 p-1.5 rounded-xl border border-white/5">
                <button onClick={() => setZoom(z => Math.max(0.1, z - 0.05))} className="p-1.5 hover:text-white"><ZoomOut size={16}/></button>
                <div className="text-[9px] font-black px-2 flex items-center">{(zoom * 100).toFixed(0)}%</div>
                <button onClick={() => setZoom(z => Math.min(1.5, z + 0.05))} className="p-1.5 hover:text-white"><ZoomIn size={16}/></button>
             </div>
             <div className="flex-1 flex items-center justify-center overflow-auto p-10 custom-scrollbar">
               <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-300">
                  {carousel?.slides[currentIndex] && (
                    <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} />
                  )}
               </div>
             </div>
             <div className="h-20 border-t border-white/5 flex items-center justify-center gap-10">
                <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(c => c - 1)} className="p-2 disabled:opacity-10"><ChevronLeft size={20}/></button>
                <div className="flex gap-2">
                  {carousel?.slides.map((_, i) => (
                    <div key={i} className={`h-1.5 rounded-full transition-all ${currentIndex === i ? 'w-8 bg-emerald-500' : 'w-1.5 bg-white/10'}`} />
                  ))}
                </div>
                <button disabled={currentIndex === (carousel?.slides.length || 1) - 1} onClick={() => setCurrentIndex(c => c + 1)} className="p-2 disabled:opacity-10"><ChevronRight size={20}/></button>
             </div>
          </main>
        </div>
      )}

      {showSaveModal && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/90 backdrop-blur-md p-6">
           <div className="w-full max-w-sm bg-zinc-900 border border-white/10 rounded-3xl p-8 space-y-6 animate-in zoom-in-95">
              <h2 className="text-lg font-black uppercase italic tracking-tighter">Salvar Projeto</h2>
              <div className="space-y-4">
                 <input type="text" placeholder="Nome" value={saveFormData.name} onChange={e => setSaveFormData({...saveFormData, name: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-xs font-bold outline-none" />
                 <input type="text" placeholder="Cliente" list="clients" value={saveFormData.client} onChange={e => setSaveFormData({...saveFormData, client: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-xs font-bold outline-none" />
                 <datalist id="clients">{clients.map(c => <option key={c} value={c} />)}</datalist>
              </div>
              <div className="flex gap-3">
                 <button onClick={() => setShowSaveModal(false)} className="flex-1 py-3 text-[10px] font-black uppercase text-zinc-500">Cancelar</button>
                 <button onClick={handleSaveToSupabase} disabled={!saveFormData.name.trim()} className="flex-1 py-3 bg-emerald-500 text-black rounded-xl text-[10px] font-black uppercase">Salvar</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;
